using Microsoft.EntityFrameworkCore;
class ProductContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Product>().ToContainer("Products");

        // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
        // Preserve the old name so existing documents and direct SQL queries
        // that reference c.Discriminator continue to work.
        modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");

        // EF Core 9: id format changed from "Product|123" to "123".
        // Preserve the old compound format so existing 500K documents
        // remain readable by FindAsync and point-reads.
        modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);

        // EF Core 9: HasIndex now throws for Cosmos entities.
        // Removed the previous HasIndex call — manage indexing via
        // the Cosmos DB container indexing policy instead.
    }
}
class Product { public int Id { get; set; } public string Sku { get; set; } }

