using System.Linq;
using Microsoft.EntityFrameworkCore;
class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O.
    // All queries and saves must use async equivalents.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator still works because we
        // configured HasDiscriminator<string>("Discriminator") in OnModelCreating.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // EF Core 9: sync APIs (ToList, SaveChanges, etc.) throw on the
        // Cosmos provider. Use ToListAsync / SaveChangesAsync instead.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

