2. class ProductContext : DbContext
3. {
4.     public DbSet<Product> Products => Set<Product>();
5.     protected override void OnModelCreating(ModelBuilder modelBuilder)
6.     {
7.         modelBuilder.Entity<Product>().ToContainer("Products");
8. 
9.         // EF Core 9: discriminator property renamed from "Discriminator" to "$type".
10.         // Preserve the old name so existing documents and direct SQL queries
11.         // that reference c.Discriminator continue to work.
12.         modelBuilder.Entity<Product>().HasDiscriminator<string>("Discriminator");
13. 
14.         // EF Core 9: id format changed from "Product|123" to "123".
15.         // Preserve the old compound format so existing 500K documents
16.         // remain readable by FindAsync and point-reads.
17.         modelBuilder.Entity<Product>().HasRootDiscriminatorInJsonId(true);
18. 
19.         // EF Core 9: HasIndex now throws for Cosmos entities.
20.         // Removed the previous HasIndex call — manage indexing via
21.         // the Cosmos DB container indexing policy instead.
22.     }
23. }
